// Compute window: last calendar month (UTC).
const now = new Date();
const end = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1));  // 1st of current month 00:00 UTC
const start = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() - 1, 1));
return [{ json: { ...$input.first().json, window_start: start.toISOString(), window_end: end.toISOString() } }];

