parameters.jsCode:
const raw = $input.first().json.response || '';
const m = raw.match(/\{[\s\S]*\}/);
if (!m) throw new Error('reporting-agent did not return JSON');
const parsed = JSON.parse(m[0]);
return [{ json: { ...parsed, client_id: $node['Compute reporting window'].json.id, period_start: $node['Compute reporting window'].json.window_start, period_end: $node['Compute reporting window'].json.window_end } }];

